//! Thoth's social support desk — gated-autonomous, public-mention support for
//! ForkJoin / `forkjoin-app`.
//!
//! A separate-but-similar lane on the social organ: instead of the general drives,
//! support has a single intent — answer people who reach out for help on a public
//! social handle. This module is the IO-free brains of it: triage a mention into a
//! [`SupportRequest`] and build the support-reply prompt. The answer itself flows
//! through the same conscience gate as the mouth (`social_presence::
//! assemble_conscience` → `propose_utterance`), so a bad/uncertain/over-budget
//! reply is held with visible residue — never posted blind.

use serde::{Deserialize, Serialize};

use crate::social_presence::PerceivedPost;

/// Lifecycle of a support ticket (the surface — forkjoin-app's inbox DO — owns the
/// authoritative status; this enum is the shared vocabulary).
#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub enum TicketStatus {
    Open,
    Answered,
    Resolved,
    Escalated,
}

/// A triaged support request extracted from a public mention.
#[derive(Serialize, Deserialize, Clone, Debug, PartialEq, Eq)]
#[serde(rename_all = "camelCase")]
pub struct SupportRequest {
    /// The social post id to reply to (the reply threads under it).
    pub post_id: String,
    pub platform: String,
    /// Handle/DID of the person asking.
    pub requester: String,
    /// The question, with leading @handles stripped.
    pub question: String,
    /// Thread/conversation context, if this mention is itself a reply.
    pub conversation_id: Option<String>,
}

/// Signals (besides a question mark) that a mention is asking for help.
const SUPPORT_SIGNALS: &[&str] = &[
    "help", "support", "issue", "problem", "error", "broken", "can't", "cannot",
    "how do i", "how to", "not working", "doesn't work", "does not work", "bug",
    "stuck", "trouble", "fail", "won't", "unable",
];

fn strip_leading_mentions(text: &str) -> String {
    let mut words: Vec<&str> = text.split_whitespace().collect();
    while words.first().map(|w| w.starts_with('@')).unwrap_or(false) {
        words.remove(0);
    }
    words.join(" ")
}

/// Triage a perceived mention: is it a support request, and what's the ask?
/// Returns `None` for non-mentions, empty text, or mentions with no help signal.
pub fn triage_mention(post: &PerceivedPost) -> Option<SupportRequest> {
    if !post.mention {
        return None;
    }
    let text = post.text.trim();
    if text.is_empty() {
        return None;
    }
    let lower = text.to_lowercase();
    let is_support = lower.contains('?') || SUPPORT_SIGNALS.iter().any(|s| lower.contains(s));
    if !is_support {
        return None;
    }
    let requester = post
        .author_username
        .clone()
        .filter(|s| !s.is_empty())
        .unwrap_or_else(|| post.author_id.clone());
    Some(SupportRequest {
        post_id: post.id.clone(),
        platform: if post.platform.is_empty() { "x".to_string() } else { post.platform.clone() },
        requester,
        question: strip_leading_mentions(text),
        conversation_id: post.reply_to_id.clone(),
    })
}

/// Build the LM prompt for a support reply. Brand-voiced, concise, non-authoritative
/// (never invent facts or commitments); `kb_excerpt` is optional retrieved docs.
pub fn build_support_reply_prompt(req: &SupportRequest, kb_excerpt: Option<&str>) -> String {
    let mut out = String::new();
    out.push_str(&format!(
        "You are ForkJoin support, replying publicly on {}. Answer the user's question \
         helpfully and concisely, in a warm, professional brand voice. Do not invent facts \
         or make commitments you cannot back; if unsure, say you will follow up and point to \
         docs. Keep it to one short post.\n",
        req.platform
    ));
    out.push_str(&format!("\n@{} asked: \"{}\"\n", req.requester, req.question));
    if let Some(kb) = kb_excerpt.filter(|s| !s.trim().is_empty()) {
        out.push_str(&format!("\nRelevant docs:\n{kb}\n"));
    }
    out.push_str("\nWrite only the reply text.");
    out
}

#[cfg(test)]
mod tests {
    use super::*;

    fn mention(text: &str) -> PerceivedPost {
        PerceivedPost {
            id: "p-1".into(),
            platform: "x".into(),
            author_username: Some("user".into()),
            text: text.into(),
            mention: true,
            ..Default::default()
        }
    }

    #[test]
    fn triage_picks_up_help_mentions() {
        let req = triage_mention(&mention("@forkjoin my login is broken, help!")).unwrap();
        assert_eq!(req.post_id, "p-1");
        assert_eq!(req.requester, "user");
        assert_eq!(req.platform, "x");
        // Leading @handle stripped from the question.
        assert_eq!(req.question, "my login is broken, help!");
    }

    #[test]
    fn triage_picks_up_questions() {
        assert!(triage_mention(&mention("@forkjoin how do I rotate my key?")).is_some());
        assert!(triage_mention(&mention("@forkjoin is edgework down right now?")).is_some());
    }

    #[test]
    fn triage_ignores_non_support_and_non_mentions() {
        // A mention with no help signal / no question.
        assert!(triage_mention(&mention("@forkjoin love the new logo")).is_none());
        // Not a mention.
        let mut p = mention("help me please");
        p.mention = false;
        assert!(triage_mention(&p).is_none());
        // Empty.
        assert!(triage_mention(&mention("   ")).is_none());
    }

    #[test]
    fn reply_prompt_includes_requester_question_and_kb() {
        let req = triage_mention(&mention("@forkjoin how to deploy? error EONFIG")).unwrap();
        let prompt = build_support_reply_prompt(&req, Some("Run a0 xr deploy --env production"));
        assert!(prompt.contains("@user asked"));
        assert!(prompt.contains("how to deploy?"));
        assert!(prompt.to_lowercase().contains("forkjoin support"));
        assert!(prompt.contains("Relevant docs:"));
        assert!(prompt.contains("a0 xr deploy"));

        // No KB → no docs section.
        let bare = build_support_reply_prompt(&req, None);
        assert!(!bare.contains("Relevant docs:"));
    }
}
